import{G as t}from"./chunks/shared-links.CZ5QUsOH.js";import{C as r,o as a,c as s,j as o,a as n,E as l,k as c,a2 as d}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"はじめに","description":"","frontmatter":{},"headers":[],"relativePath":"ja/introduction.md","filePath":"ja/introduction.md"}'),p={name:"ja/introduction.md"},u=Object.assign(p,{setup(h){return(g,e)=>{const i=r("YoutubePlayer");return a(),s("div",null,[e[0]||(e[0]=o("h1",{id:"はじめに",tabindex:"-1"},[o("i",{class:"ph ph-hand-waving"}),n(" はじめに "),o("a",{class:"header-anchor",href:"#はじめに","aria-label":'Permalink to "<i class="ph ph-hand-waving"></i> はじめに"'},"​")],-1)),l(i,{src:c(t).youtubeVideo},null,8,["src"]),e[1]||(e[1]=d('<p><strong>Web Adaptive Performance (WebAP)</strong> は、Unity WebGLアプリケーションの動的最適化ツールです。</p><p>強力なPCから性能の低いスマートフォンまで、幅広いデバイスにわたって、視覚的な品質と安定したFPSのバランスを見つけるのに役立ちます。固定された制限に依存するのではなく、プラグインはフレームタイミングをリアルタイムで分析します。パフォーマンス低下の根本原因を特定し、安定するまでスムーズに負荷を軽減し、パフォーマンスの余裕（Performance Headroom）が得られれば品質を回復させます。</p><div class="tip custom-block"><p class="custom-block-title">デバイスへの適応</p><p>デフォルトでは、Unityプロジェクトを最大品質設定で構成してください。現在のデバイスがその負荷を処理できない場合、プラグインは実行時（Runtime）に自動的に負荷を軽減します。</p></div><h2 id="なぜwebapを選ぶのか" tabindex="-1">なぜWebAPを選ぶのか？ <a class="header-anchor" href="#なぜwebapを選ぶのか" aria-label="Permalink to &quot;なぜWebAPを選ぶのか？&quot;">​</a></h2><p><strong><i class="ph-bold ph-x"></i> 公式のAdaptive Performanceパッケージではない理由は？</strong><br> 公式のUnityパッケージは強力なツールですが、WebGLとは根本的に互換性がありません。これは2種類のプロバイダーに依存しており、どちらもブラウザの制限によって阻害されます。</p><ol><li><strong>ネイティブプロバイダー (Android):</strong> 熱データを取得し、周波数を管理するためにシステムAPIに依存しています。ブラウザのサンドボックスはハードウェアへのすべてのアクセスをブロックするため、このアプローチは不可能です。新しいWeb標準（<em>Compute Pressure API</em>など）はCPUのみを監視し、3Dグラフィックスに関する正確なデータを提供しません。</li><li><strong>基本プロバイダー (Basic Provider):</strong> Unityのクロスプラットフォームな数学的プロバイダー。これは <code>FrameTimingManager</code> に依存しています。しかし、エンジンが機能するためには、高精度のハードウェアGPUタイマーが必要ですが、ブラウザではセキュリティ上の理由から（<em>Spectre/Meltdown</em>攻撃を防ぐため）ブロックされるか、または厳重に難読化されています。その結果、公式のBasic Providerは実際にはWebGLで初期化されません。</li></ol><p><strong><i class="ph-bold ph-check"></i> WebAPのソリューション:</strong> 私たちは、Webの特性に特化したアプローチを設計しました。WebAPも <code>FrameTimingManager</code> を利用しますが、ブロックされたGPUタイマーに厳密に依存するのではなく、安全なヒューリスティック分析を使用します。ブラウザの異常（Emscriptenでの <code>setTimeout</code> によるメトリクスの歪みなど）を回避し、純粋な数学的計算によってボトルネック（CPU対GPU）を算出します。これにより、あらゆるブラウザで合法かつ安定して動作するAAAクラスの最適化システムが実現します。</p><p><strong><i class="ph-bold ph-x"></i> なぜ標準的なスケーラースクリプトではないのか？</strong><br> 従来のソリューションでは、遅延の兆候が初めて現れたときに、単に画面解像度を下げるだけです。アプリケーションがレンダリングではなくCPUの計算（物理演算、スクリプト、ロジック）によってカクついている場合、これは無意味です。</p><p><strong><i class="ph-fill ph-check-fat"></i> WebAPの仕組み:</strong></p><ul><li><i class="ph-fill ph-brain"></i> <strong>ボトルネックの検出 (Bottleneck Detection)</strong><br> プラグインは、フレームを制限しているのがCPUかGPUかを数学的に判断します。物理演算が遅延している場合、システムは画面解像度を下げずに物理演算を簡略化します。この目的のために、12個以上の独立したスケーラー（シャドウ、LOD、レイヤーカリングなど）が用意されています。</li><li><i class="ph-fill ph-hand-palm"></i> <strong>アンチヨーヨー・ペナルティシステム (Anti Yo-Yo Penalty System)</strong><br> 品質のちらつき（Quality flickering）という、動的解像度における一般的な問題を解決します。グラフィックの向上が即座にFPSの低下を引き起こした場合、システムは一時的なペナルティロックアウト（Penalty Lockout）を実施し、さらなる向上をブロックします。</li><li><i class="ph-fill ph-layout"></i> <strong>UIの鮮明さを保持</strong><br><code>RenderTexture</code> を介したスケールモードを選択すると、3Dワールドの解像度は下がりますが、インターフェースはネイティブブラウザスケーリング（Native Browser Scaling）に維持されます。カスタムの <code>WebScaledPhysicsRaycaster</code> コンポーネントが光線の座標を自動的に再計算するため、フレームの圧縮に関係なく、3Dオブジェクトへのクリックは完璧に機能します。</li><li><i class="ph-fill ph-lightning"></i> <strong>Zero-GC アーキテクチャ</strong><br> プロジェクト全体は、厳格なメモリ節約を念頭に置いて設計されています。コアはO(1)のリングバッファを使用し、<code>Update</code> ループ内でのメモリ割り当て（アロケーション）を一切行いません。結果として、プラグインはガベージコレクタ（GC）を起動させません。</li><li><i class="ph-fill ph-broom"></i> <strong>厳格なビルドのクリーンアップ</strong><br> 多くのアセットは、プレハブやテクスチャを <code>Resources</code> フォルダに配置し（エンジンにビルドに強制的に含めさせ）、リリースビルドを肥大化させます。WebAPのアーキテクチャはこのエラーを回避します。シーンに明示的に追加されない限り、すべてのユーティリティとダッシュボードUIはコンパイル時に自動的に削除されます。軽量なコアだけが最終プロジェクトに到達します。</li><li><i class="ph-fill ph-gear"></i> <strong>プラグアンドプレイの統合</strong><br> 設定は <em>Project Settings</em> 内の統合されたインターフェースに集約されます。プラグインは自動的にビルドに注入されるため、マネージャープレハブをシーンに手動で配置する必要はありません。</li></ul><h2 id="互換性" tabindex="-1">互換性 <a class="header-anchor" href="#互換性" aria-label="Permalink to &quot;互換性&quot;">​</a></h2><ul><li><strong>Unityバージョン:</strong> <code>2020.3 LTS</code> 以降。プラグインは最新のAPIを活用し、新しいエンジン機能（Unity 6000.2+以降の <code>Mesh LOD Threshold</code> サポートなど）を自動的に採用します。</li><li><strong>レンダーパイプライン:</strong> Built-in Render Pipeline (BiRP) と Universal Render Pipeline (URP) の両方を完全にサポートします。</li></ul>',12))])}}});export{m as __pageData,u as default};
